class Solution {
public:
    string smallestEquivalentString(string s1, string s2, string baseStr) {
        vector<int> parent(26);
        for (int i = 0; i < 26; ++i) {
            parent[i] = i;
        }

        function<int(int)> find = [&](int x) {
            if (x != parent[x]) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        function<void(int, int)> unionSets = [&](int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX != rootY) {
                if (rootX < rootY) {
                    parent[rootY] = rootX;
                } else {
                    parent[rootX] = rootY;
                }
            }
        };

        for (int i = 0; i < s1.size(); ++i) {
            unionSets(s1[i] - 'a', s2[i] - 'a');
        }

        string result;
        for (char c : baseStr) {
            result += 'a' + find(c - 'a');
        }
        return result;
    }
};
